+    /// Canonicalize rendered text for deterministic snapshot hashing.
+    fn canonical_text(text: &Text) -> String {
+        text.lines()
+            .iter()
+            .map(|line| {
+                line.spans()
+                    .iter()
+                    .map(|span| span.content.as_ref())
+                    .collect::<String>()
+                    .trim_end()
+                    .to_string()
+            })
+            .collect::<Vec<_>>()
+            .join("\n")
+    }
